const results = [];

for(const channel of $input.all()){
for (const item of channel.json.items) { 
    results.push({ 
      videoId: item.id.videoId, 
      title: item.snippet.title, 
      publishedAt: item.snippet.publishedAt, 
      channelId: item.snippet.channelId, 
      url: `https://www.youtube.com/watch?v=${item.id.videoId}`,
    });
}}

return results;

const now = new Date();
const lastWeek = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

let news = $input.first().json.data
// Filter items from the last 7 days
.filter(n => new Date(n.isoDate) > lastWeek)
// Sort newest → oldest
.sort((a, b) => new Date(b.isoDate) - new Date(a.isoDate))
// Limit to 10 most recent
.slice(0, 10)
// Map to dictionary format
.map(n => ({
  "Info source": n["content:encodedSnippet"],
}));

// Return in n8n format
return news.map(item => ({ json: item }));

