import re

def parse_tools(text):
  # Pattern: separator, optional whitespace, **Tool Name**, then capture description until next separator
  text = "______\n\n" + text
  pattern = r'_{6,}\s*\*\*(.*?)\*\*\s*(.*?)(?=_{6,}|$)'
  matches = re.findall(pattern, text, re.DOTALL)

  result = []
  for tool_name, description in matches:
      result.append({
          "toolName": tool_name.strip(),
          "toolDescription": f"**{tool_name.strip()}**\n" +     description.strip()
      })

  return result

return parse_tools(_input.first().json.output)

